class Solution:
    def minTime(self, skill, mana):
        n = len(skill)
        m = len(mana)
        available = [0] * n
        finish_last = 0
        for j in range(m):
            prefix = []
            acc = 0
            for i in range(n):
                acc += skill[i] * mana[j]
                prefix.append(acc)
            start = 0
            for i in range(n):
                before = 0 if i == 0 else prefix[i - 1]
                cand = available[i] - before
                if cand > start:
                    start = cand
            for i in range(n):
                available[i] = start + prefix[i]
            finish_last = start + prefix[-1]
        return finish_last

