var minTime = function(skill, mana) {
    const n = skill.length, m = mana.length;
    let prefixPrev = new Array(n);
    let acc = 0n;
    for (let i = 0; i < n; i++) {
        acc += BigInt(skill[i]) * BigInt(mana[0]);
        prefixPrev[i] = acc;
    }
    let S = 0n;
    for (let j = 1; j < m; j++) {
        const prefixCur = new Array(n);
        acc = 0n;
        for (let i = 0; i < n; i++) {
            acc += BigInt(skill[i]) * BigInt(mana[j]);
            prefixCur[i] = acc;
        }
        let maxVal = -1n;
        for (let i = 0; i < n; i++) {
            const prevAtI = prefixPrev[i];
            const curBefore = i === 0 ? 0n : prefixCur[i - 1];
            const diff = prevAtI - curBefore;
            if (diff > maxVal) maxVal = diff;
        }
        S += maxVal;
        prefixPrev = prefixCur;
    }
    const total = S + prefixPrev[n - 1];
    return Number(total);
};
